{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "permissions": {
    "allow": [
      "Bash(npm run build:*)",
      "Bash(npm run dev:*)",
      "Bash(npm run preview:*)",
      "Bash(npm run astro:*)",
      "Bash(npx astro:*)",
      "Bash(git add:*)",
      "Bash(git commit:*)",
      "Bash(git push:*)",
      "Bash(git status:*)",
      "Bash(git diff:*)",
      "Bash(git log:*)",
      "Bash(npm install:*)",
      "Bash(npm uninstall:*)",
      "Bash(npx wrangler:*)"
    ],
    "deny": [
      "Bash(rm -rf:*)",
      "Bash(git push --force:*)",
      "Bash(git reset --hard:*)"
    ]
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": {
          "toolName": "Write",
          "filePath": "**/*.{ts,tsx,astro,js,mjs}"
        },
        "hooks": [
          {
            "type": "command",
            "command": "npx prettier --write \"$CLAUDE_FILE_PATH\" 2>/dev/null || true"
          }
        ]
      }
    ],
    "PreCommit": [
      {
        "type": "command",
        "command": "npm run build 2>/dev/null || echo 'Build check skipped - project not initialized yet'"
      }
    ]
  },
  "context": {
    "include": [
      "CLAUDE.md",
      "src/content/config.ts",
      "astro.config.mjs",
      "tailwind.config.mjs"
    ],
    "exclude": [
      "node_modules/**",
      "dist/**",
      ".astro/**",
      "public/images/**"
    ]
  },
  "model": {
    "default": "sonnet",
    "thinking": true
  }
}

