import { defineCollection, z } from 'astro:content';

/**
 * Property listing schema
 * Defines the structure for rental property content
 */
const properties = defineCollection({
  type: 'content',
  schema: z.object({
    // Identity
    title: z.string().min(1),
    slug: z.string().regex(/^[a-z0-9-]+$/, 'Slug must be lowercase with hyphens'),
    status: z.enum(['available', 'pending', 'rented']),
    featured: z.boolean().default(false),

    // Pricing
    rent: z.number().positive(),
    deposit: z.number().nonnegative(),

    // Property details
    beds: z.number().int().nonnegative(),
    baths: z.number().positive(),
    sqft: z.number().positive().optional(),
    propertyType: z.enum(['apartment', 'house', 'townhome', 'condo', 'duplex']),

    // Location (masked for privacy - no exact address)
    neighborhood: z.string().min(1),
    city: z.string().min(1),
    state: z.string().length(2),
    zipCode: z.string().optional(),

    // Features
    features: z.array(z.string()).default([]),
    petPolicy: z
      .enum(['no-pets', 'cats-only', 'dogs-only', 'cats-dogs', 'negotiable'])
      .default('no-pets'),
    parking: z.enum(['none', 'street', 'lot', 'garage', 'covered']).default('none'),
    laundry: z.enum(['none', 'shared', 'in-unit', 'hookups']).default('none'),

    // Media
    photos: z.array(z.string()).min(1),
    virtualTourUrl: z.string().url().optional(),

    // Application
    applyUrl: z.string().url(),
    applicationFee: z.number().nonnegative().optional(),
    stripePaymentLink: z.string().url().optional(),

    // Dates
    availableDate: z.coerce.date().optional(),
    publishedDate: z.coerce.date(),
    updatedDate: z.coerce.date().optional(),
  }),
});

/**
 * Static pages schema
 * For About, FAQ, etc.
 */
const pages = defineCollection({
  type: 'content',
  schema: z.object({
    title: z.string().min(1),
    description: z.string().optional(),
    updatedDate: z.coerce.date().optional(),
  }),
});

/**
 * FAQ schema
 * Structured Q&A content
 */
const faq = defineCollection({
  type: 'data',
  schema: z.object({
    title: z.string(),
    questions: z.array(
      z.object({
        question: z.string(),
        answer: z.string(),
      })
    ),
  }),
});

/**
 * Site settings schema
 * Contact info, business details
 */
const settings = defineCollection({
  type: 'data',
  schema: z.object({
    phone: z.string().optional(),
    email: z.string().email(),
    address: z.string().optional(),
    hours: z.string().optional(),
    socialLinks: z
      .object({
        facebook: z.string().url().optional(),
        instagram: z.string().url().optional(),
      })
      .optional(),
  }),
});

export const collections = {
  properties,
  pages,
  faq,
  settings,
};

