@import "tailwindcss";

/* OakStone Properties - Design System */

/* Custom CSS Variables (Brand Colors - TBD by owner) */
@theme {
  /* Primary - Earthy stone/brown tones (placeholder) */
  --color-primary-50: #faf5f0;
  --color-primary-100: #f0e6d8;
  --color-primary-200: #e0ccb0;
  --color-primary-300: #c9a87a;
  --color-primary-400: #b38b52;
  --color-primary-500: #9a7340;
  --color-primary-600: #7d5c34;
  --color-primary-700: #64492c;
  --color-primary-800: #523d28;
  --color-primary-900: #453525;

  /* Accent - Oak leaf green (placeholder) */
  --color-accent-50: #f4f9f4;
  --color-accent-100: #e5f1e5;
  --color-accent-200: #cce4cd;
  --color-accent-300: #a3cca5;
  --color-accent-400: #72ad76;
  --color-accent-500: #4d8f52;
  --color-accent-600: #3b7340;
  --color-accent-700: #315c35;
  --color-accent-800: #2a4a2e;
  --color-accent-900: #243d27;

  /* Typography Scale */
  --font-family-sans: "Inter", system-ui, -apple-system, sans-serif;
  --font-family-display: "Inter", system-ui, -apple-system, sans-serif;

  /* Touch targets - Mobile accessibility */
  --min-touch-target: 48px;

  /* Container widths */
  --container-sm: 640px;
  --container-md: 768px;
  --container-lg: 1024px;
  --container-xl: 1280px;
}

/* Base styles */
html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-family-sans);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Focus styles for accessibility */
:focus-visible {
  outline: 2px solid var(--color-primary-500);
  outline-offset: 2px;
}

/* Skip link for keyboard navigation */
.skip-link {
  position: absolute;
  top: -40px;
  left: 0;
  background: var(--color-primary-600);
  color: white;
  padding: 8px 16px;
  z-index: 100;
  transition: top 0.3s;
}

.skip-link:focus {
  top: 0;
}

/* Utility classes */
.touch-target {
  min-height: var(--min-touch-target);
  min-width: var(--min-touch-target);
}

/* Property card hover effect */
.property-card {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.property-card:hover {
  transform: translateY(-2px);
  box-shadow:
    0 10px 15px -3px rgb(0 0 0 / 0.1),
    0 4px 6px -4px rgb(0 0 0 / 0.1);
}

/* Status badges */
.badge-available {
  background-color: var(--color-accent-100);
  color: var(--color-accent-700);
}

.badge-pending {
  background-color: #fef3c7;
  color: #92400e;
}

.badge-rented {
  background-color: #fee2e2;
  color: #991b1b;
}

/* Image lazy loading placeholder */
.img-placeholder {
  background: linear-gradient(90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

/* Print styles */
@media print {
  .no-print {
    display: none !important;
  }
}

