@import "tailwindcss";

/* OakStone Properties - Design System */
/* Color palette derived from logo: Navy blue (house) + Forest green (oak leaves) */

@theme {
  /* Primary - Navy/Teal Blue (house outline, "PROPERTIES" text) */
  --color-primary-50: #eef5f7;
  --color-primary-100: #d5e7ec;
  --color-primary-200: #afd0da;
  --color-primary-300: #7fb2c2;
  --color-primary-400: #4d8fa3;
  --color-primary-500: #366f84;
  --color-primary-600: #1e4d5c;
  --color-primary-700: #1a4150;
  --color-primary-800: #183742;
  --color-primary-900: #152d36;
  --color-primary-950: #0d1c22;

  /* Accent - Forest Green (oak leaves, "OakStone" text) */
  --color-accent-50: #f0f7f0;
  --color-accent-100: #dcebdc;
  --color-accent-200: #bbd8bb;
  --color-accent-300: #8fbd8f;
  --color-accent-400: #5fa05f;
  --color-accent-500: #458b45;
  --color-accent-600: #357035;
  --color-accent-700: #2d5a2d;
  --color-accent-800: #274927;
  --color-accent-900: #223c22;
  --color-accent-950: #0f1f0f;

  /* Typography Scale */
  --font-family-sans: "Inter", system-ui, -apple-system, sans-serif;
  --font-family-display: "Inter", system-ui, -apple-system, sans-serif;

  /* Touch targets - Mobile accessibility */
  --min-touch-target: 48px;

  /* Container widths */
  --container-sm: 640px;
  --container-md: 768px;
  --container-lg: 1024px;
  --container-xl: 1280px;
}

/* ============================================
   THEME SYSTEM - Light/Dark Mode
   ============================================ */

:root {
  /* Light mode defaults */
  --bg-primary: #ffffff;
  --bg-secondary: #f9fafb;
  --bg-tertiary: #f3f4f6;
  --bg-inverse: #1f2937;

  --text-primary: #111827;
  --text-secondary: #4b5563;
  --text-tertiary: #6b7280;
  --text-inverse: #f9fafb;

  --border-primary: #e5e7eb;
  --border-secondary: #d1d5db;

  --shadow-color: 0 0 0;

  color-scheme: light;
}

/* Dark mode */
:root.dark {
  --bg-primary: #111827;
  --bg-secondary: #1f2937;
  --bg-tertiary: #374151;
  --bg-inverse: #f9fafb;

  --text-primary: #f9fafb;
  --text-secondary: #d1d5db;
  --text-tertiary: #9ca3af;
  --text-inverse: #111827;

  --border-primary: #374151;
  --border-secondary: #4b5563;

  --shadow-color: 0 0 0;

  color-scheme: dark;
}

/* System preference fallback (when no class is set) */
@media (prefers-color-scheme: dark) {
  :root:not(.light):not(.dark) {
    --bg-primary: #111827;
    --bg-secondary: #1f2937;
    --bg-tertiary: #374151;
    --bg-inverse: #f9fafb;

    --text-primary: #f9fafb;
    --text-secondary: #d1d5db;
    --text-tertiary: #9ca3af;
    --text-inverse: #111827;

    --border-primary: #374151;
    --border-secondary: #4b5563;

    color-scheme: dark;
  }
}

/* ============================================
   BASE STYLES
   ============================================ */

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-family-sans);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background-color: var(--bg-secondary);
  color: var(--text-primary);
  transition: background-color 0.2s ease, color 0.2s ease;
}

/* Focus styles for accessibility */
:focus-visible {
  outline: 2px solid var(--color-primary-500);
  outline-offset: 2px;
}

/* Skip link for keyboard navigation */
.skip-link {
  position: absolute;
  top: -40px;
  left: 0;
  background: var(--color-primary-600);
  color: white;
  padding: 8px 16px;
  z-index: 100;
  transition: top 0.3s;
}

.skip-link:focus {
  top: 0;
}

/* ============================================
   THEME-AWARE UTILITIES
   ============================================ */

/* Background utilities */
.bg-theme-primary {
  background-color: var(--bg-primary);
}

.bg-theme-secondary {
  background-color: var(--bg-secondary);
}

.bg-theme-tertiary {
  background-color: var(--bg-tertiary);
}

/* Text utilities */
.text-theme-primary {
  color: var(--text-primary);
}

.text-theme-secondary {
  color: var(--text-secondary);
}

.text-theme-tertiary {
  color: var(--text-tertiary);
}

/* Border utilities */
.border-theme-primary {
  border-color: var(--border-primary);
}

.border-theme-secondary {
  border-color: var(--border-secondary);
}

/* ============================================
   COMPONENT STYLES
   ============================================ */

/* Touch targets */
.touch-target {
  min-height: var(--min-touch-target);
  min-width: var(--min-touch-target);
}

/* Property card hover effect */
.property-card {
  background-color: var(--bg-primary);
  border-color: var(--border-primary);
  transition: transform 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
}

.property-card:hover {
  transform: translateY(-2px);
  box-shadow:
    0 10px 15px -3px rgb(var(--shadow-color) / 0.1),
    0 4px 6px -4px rgb(var(--shadow-color) / 0.1);
}

:root.dark .property-card:hover {
  box-shadow:
    0 10px 15px -3px rgb(0 0 0 / 0.3),
    0 4px 6px -4px rgb(0 0 0 / 0.2);
}

/* Status badges */
.badge-available {
  background-color: var(--color-accent-100);
  color: var(--color-accent-700);
}

:root.dark .badge-available {
  background-color: var(--color-accent-900);
  color: var(--color-accent-300);
}

.badge-pending {
  background-color: #fef3c7;
  color: #92400e;
}

:root.dark .badge-pending {
  background-color: #78350f;
  color: #fef3c7;
}

.badge-rented {
  background-color: #f3f4f6;
  color: #6b7280;
}

:root.dark .badge-rented {
  background-color: #374151;
  color: #9ca3af;
}

/* Image lazy loading placeholder */
.img-placeholder {
  background: linear-gradient(90deg, var(--bg-tertiary) 25%, var(--bg-secondary) 50%, var(--bg-tertiary) 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

/* Theme toggle button */
.theme-toggle {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: 0.5rem;
  background-color: transparent;
  color: var(--text-secondary);
  transition: background-color 0.2s ease, color 0.2s ease;
}

.theme-toggle:hover {
  background-color: var(--bg-tertiary);
  color: var(--text-primary);
}

.theme-toggle svg {
  width: 20px;
  height: 20px;
}

/* Hide icon based on theme */
.theme-toggle .icon-sun {
  display: none;
}

.theme-toggle .icon-moon {
  display: block;
}

:root.dark .theme-toggle .icon-sun {
  display: block;
}

:root.dark .theme-toggle .icon-moon {
  display: none;
}

/* For system preference (before JS loads) */
@media (prefers-color-scheme: dark) {
  :root:not(.light):not(.dark) .theme-toggle .icon-sun {
    display: block;
  }
  :root:not(.light):not(.dark) .theme-toggle .icon-moon {
    display: none;
  }
}

/* Gradient backgrounds with dark mode support */
.gradient-primary {
  background: linear-gradient(135deg, var(--color-primary-600) 0%, var(--color-primary-800) 100%);
}

:root.dark .gradient-primary {
  background: linear-gradient(135deg, var(--color-primary-700) 0%, var(--color-primary-900) 100%);
}

/* Card styles */
.card {
  background-color: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: 0.75rem;
}

/* Input styles */
input, textarea, select {
  background-color: var(--bg-primary);
  border-color: var(--border-secondary);
  color: var(--text-primary);
}

input:focus, textarea:focus, select:focus {
  border-color: var(--color-primary-500);
}

input::placeholder, textarea::placeholder {
  color: var(--text-tertiary);
}

/* Details/Summary (FAQ) */
details summary {
  cursor: pointer;
}

details[open] summary {
  margin-bottom: 0;
}

/* Prose/Markdown content dark mode */
.prose {
  color: var(--text-primary);
}

.prose h1, .prose h2, .prose h3, .prose h4 {
  color: var(--text-primary);
}

.prose p, .prose li {
  color: var(--text-secondary);
}

.prose a {
  color: var(--color-primary-600);
}

:root.dark .prose a {
  color: var(--color-primary-400);
}

.prose strong {
  color: var(--text-primary);
}

/* ============================================
   PRINT STYLES
   ============================================ */

@media print {
  .no-print {
    display: none !important;
  }
}

