---
// Header component with responsive navigation and theme toggle
const navLinks = [
  { href: '/', label: 'Home' },
  { href: '/properties', label: 'Properties' },
  { href: '/about', label: 'About' },
  { href: '/contact', label: 'Contact' },
];

const currentPath = Astro.url.pathname;
---

<header class="bg-theme-primary shadow-sm sticky top-0 z-50 border-b border-theme-primary">
  <nav class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8" aria-label="Main navigation">
    <div class="flex justify-between items-center h-16">
      <!-- Logo -->
      <a href="/" class="flex items-center gap-2">
        <!-- Light mode logo (dark colors) -->
        <img
          src="/images/logos/logo.png"
          alt="OakStone Properties"
          class="h-10 w-auto logo-light"
          width="160"
          height="40"
        />
        <!-- Dark mode logo (light colors) -->
        <img
          src="/images/logos/logo_white.png"
          alt="OakStone Properties"
          class="h-10 w-auto logo-dark hidden"
          width="160"
          height="40"
        />
      </a>

      <!-- Desktop Navigation -->
      <div class="hidden md:flex items-center gap-1">
        {
          navLinks.map((link) => (
            <a
              href={link.href}
              class:list={[
                'px-4 py-2 rounded-lg text-sm font-medium transition-colors touch-target flex items-center',
                currentPath === link.href
                  ? 'bg-primary-100 text-primary-700 dark:bg-primary-900 dark:text-primary-200'
                  : 'text-theme-secondary hover:bg-theme-tertiary hover:text-theme-primary',
              ]}
              aria-current={currentPath === link.href ? 'page' : undefined}
            >
              {link.label}
            </a>
          ))
        }

        <!-- Theme Toggle -->
        <button
          type="button"
          class="theme-toggle ml-2"
          aria-label="Toggle dark mode"
          id="theme-toggle-desktop"
        >
          <!-- Sun icon (shown in dark mode) -->
          <svg class="icon-sun" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
          </svg>
          <!-- Moon icon (shown in light mode) -->
          <svg class="icon-moon" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
          </svg>
        </button>
      </div>

      <!-- Mobile Menu Button & Theme Toggle -->
      <div class="flex items-center gap-2 md:hidden">
        <!-- Theme Toggle (Mobile) -->
        <button
          type="button"
          class="theme-toggle"
          aria-label="Toggle dark mode"
          id="theme-toggle-mobile"
        >
          <svg class="icon-sun" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
          </svg>
          <svg class="icon-moon" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
          </svg>
        </button>

        <!-- Menu Button -->
        <button
          type="button"
          class="p-2 rounded-lg text-theme-secondary hover:bg-theme-tertiary touch-target"
          aria-expanded="false"
          aria-controls="mobile-menu"
          aria-label="Open menu"
          id="mobile-menu-button"
        >
          <svg class="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16" />
          </svg>
        </button>
      </div>
    </div>

    <!-- Mobile Navigation -->
    <div id="mobile-menu" class="md:hidden hidden pb-4">
      <div class="flex flex-col gap-1 pt-2 border-t border-theme-primary">
        {
          navLinks.map((link) => (
            <a
              href={link.href}
              class:list={[
                'px-4 py-3 rounded-lg text-base font-medium transition-colors touch-target',
                currentPath === link.href
