---
import '../styles/global.css';
import Header from '../components/layout/Header.astro';
import Footer from '../components/layout/Footer.astro';
import { SEO } from 'astro-seo';

interface Props {
  title: string;
  description?: string;
  ogImage?: string;
  noindex?: boolean;
}

const {
  title,
  description = 'Quality rental properties from OakStone Properties. Browse available homes and apartments.',
  ogImage = '/og-default.jpg',
  noindex = false,
} = Astro.props;

const siteTitle = title ? `${title} | OakStone Properties` : 'OakStone Properties';
const canonicalURL = new URL(Astro.url.pathname, Astro.site);
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />

    <!-- Theme initialization script (runs immediately to prevent flash) -->
    <script is:inline>
      (function() {
        const stored = localStorage.getItem('theme');
        const systemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

        if (stored === 'dark' || (stored === null && systemDark)) {
          document.documentElement.classList.add('dark');
        } else if (stored === 'light') {
          document.documentElement.classList.add('light');
        }
