---
// Reusable property card component
import type { CollectionEntry } from 'astro:content';

interface Props {
  property: CollectionEntry<'properties'>;
  showStatus?: boolean;
}

const { property, showStatus = true } = Astro.props;
const { data } = property;

// Status badge styles
const statusStyles = {
  available: 'badge-available',
  pending: 'badge-pending',
  rented: 'badge-rented',
} as const;

const statusLabels = {
  available: 'Available',
  pending: 'Pending',
  rented: 'Rented',
} as const;

// Pet policy labels
const petLabels = {
  'no-pets': 'No Pets',
  'cats-only': 'Cats OK',
  'dogs-only': 'Dogs OK',
  'cats-dogs': 'Pets OK',
  'negotiable': 'Pets Negotiable',
} as const;
---

<article class="property-card rounded-xl overflow-hidden shadow-md border border-theme-primary transition-shadow hover:shadow-lg">
  <!-- Property Image -->
  <a href={`/properties/${property.slug}`} class="block">
    <div class="aspect-video bg-theme-tertiary relative overflow-hidden">
      <img
        src={data.photos[0]}
        alt={`Photo of ${data.title}`}
        class="w-full h-full object-cover transition-transform hover:scale-105"
        loading="lazy"
      />
      {showStatus && (
        <span class={`absolute top-3 left-3 px-3 py-1 rounded-full text-sm font-medium ${statusStyles[data.status]}`}>
          {statusLabels[data.status]}
        </span>
      )}
      {data.featured && data.status === 'available' && (
        <span class="absolute top-3 right-3 px-3 py-1 rounded-full text-sm font-medium bg-accent-600 text-white">
          Featured
        </span>
      )}
    </div>
  </a>

  <!-- Property Details -->
  <div class="p-5">
    <h3 class="text-lg font-semibold text-theme-primary mb-2">
      <a href={`/properties/${property.slug}`} class="hover:text-primary-500 transition-colors">
        {data.title}
      </a>
    </h3>

    <p class="text-theme-secondary text-sm mb-3">
      {data.neighborhood}, {data.city}
    </p>

    <!-- Property Stats -->
    <div class="flex items-center gap-4 text-sm text-theme-tertiary mb-4">
      <span class="flex items-center gap-1" title="Bedrooms">
        <svg class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
        </svg>
        {data.beds} bed
      </span>
      <span class="flex items-center gap-1" title="Bathrooms">
        <svg class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 14v3m4-3v3m4-3v3M3 21h18M3 10h18M3 7l9-4 9 4M4 10h16v11H4V10z" />
        </svg>
        {data.baths} bath
      </span>
      {data.sqft && (
        <span class="flex items-center gap-1" title="Square feet">
          <svg class="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" aria-hidden="true">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
          </svg>
          {data.sqft.toLocaleString()} sqft
        </span>
      )}
    </div>

    <!-- Tags row -->
    <div class="flex flex-wrap gap-2 mb-4">
      <span class="text-xs px-2 py-1 bg-theme-tertiary text-theme-secondary rounded-full capitalize">
        {data.propertyType}
      </span>
      {data.petPolicy !== 'no-pets' && (
        <span class="text-xs px-2 py-1 bg-accent-100 text-accent-700 rounded-full">
          {petLabels[data.petPolicy]}
        </span>
      )}
      {data.laundry === 'in-unit' && (
        <span class="text-xs px-2 py-1 bg-primary-100 text-primary-700 rounded-full">
          In-Unit Laundry
        </span>
      )}
    </div>

    <!-- Price and CTA -->
    <div class="flex items-center justify-between pt-4 border-t border-theme-primary">
      <p class="text-xl font-bold text-primary-500">
        ${data.rent.toLocaleString()}<span class="text-sm font-normal text-theme-tertiary">/mo</span>
      </p>
      <a
        href={`/properties/${property.slug}`}
        class="text-sm font-medium text-primary-500 hover:text-primary-600 transition-colors"
      >
        View Details &rarr;
      </a>
    </div>
  </div>
</article>

