---
import BaseLayout from '../../layouts/BaseLayout.astro';
import PropertyCard from '../../components/property/PropertyCard.astro';
import { getCollection } from 'astro:content';

// Get all properties, sorted by status (available first) then by date
const allProperties = await getCollection('properties');
const sortedProperties = allProperties.sort((a, b) => {
  // Status priority: available > pending > rented
  const statusOrder = { available: 0, pending: 1, rented: 2 };
  const statusDiff = statusOrder[a.data.status] - statusOrder[b.data.status];
  if (statusDiff !== 0) return statusDiff;

  // Then by publish date (newest first)
  return b.data.publishedDate.getTime() - a.data.publishedDate.getTime();
});

// Count by status for display
const availableCount = allProperties.filter(p => p.data.status === 'available').length;
const pendingCount = allProperties.filter(p => p.data.status === 'pending').length;
const rentedCount = allProperties.filter(p => p.data.status === 'rented').length;

// Get unique values for filters
const propertyTypes = [...new Set(allProperties.map(p => p.data.propertyType))];
const neighborhoods = [...new Set(allProperties.map(p => p.data.neighborhood))].sort();
const cities = [...new Set(allProperties.map(p => p.data.city))].sort();

// Price ranges for display
const prices = allProperties.filter(p => p.data.status === 'available').map(p => p.data.rent);
const minPrice = prices.length > 0 ? Math.min(...prices) : 0;
const maxPrice = prices.length > 0 ? Math.max(...prices) : 0;
